const numbersToWords=x=>{const u=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(x<0x14)return u[x];if(x<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](x/0xa)]+(x%0xa?'\x20'+u[x%0xa]:'');if(x<0x3e8){const Y=Math['floor'](x/0x64),j=x%0x64;return(0x1===Y?'εκατό':0x2===Y?'διακόσια':0x3===Y?'τριακόσια':0x4===Y?'τετρακόσια':0x5===Y?'πεντακόσια':0x6===Y?'εξακόσια':0x7===Y?'επτακόσια':0x8===Y?'οκτακόσια':0x9===Y?'εννιακόσια':'')+(j?'\x20'+numbersToWords(j):'');}return x<0xf4240?numbersToWords(Math['floor'](x/0x3e8))+'\x20χιλιάδες'+(x%0x3e8?'\x20'+numbersToWords(x%0x3e8):''):numbersToWords(Math['floor'](x/0xf4240))+'\x20εκατομμύρια'+(x%0xf4240?'\x20'+numbersToWords(x%0xf4240):'');},numberToText=(x,u='money')=>{const Y=Math['floor'](x),j=Math['round'](0x64*(x-Y));let z=numbersToWords(Y),k=j>0x0?numbersToWords(j):'';switch(u){case'money':return k?z+'\x20ευρώ\x20και\x20'+k+'\x20λεπτά':z+'\x20ευρώ';case'time':return k?z+'\x20ώρες\x20και\x20'+k+'\x20λεπτά':z+'\x20ώρες';default:return k?z+'\x20και\x20'+k:''+z;}};